{
var seed = GetInt(parameters, "seed", context.Seed);
var density = Math.Max(2, GetInt(parameters, "density", 8));
var ringDistort = GetFloat(parameters, "ringDistort", 0.3f);
var grainContrast = GetFloat(parameters, "grainContrast", 0.5f);
var ringSharpness = GetFloat(parameters, "ringSharpness", 0.7f);
var colorA = GetColor(parameters, "colorA", Color.FromRgb(160, 120, 80));
var colorB = GetColor(parameters, "colorB", Color.FromRgb(100, 70, 40));
var colorVar = GetFloat(parameters, "colorVariation", 0.1f);
var brightness = GetFloat(parameters, "brightness", 0f);
var contrast = GetFloat(parameters, "contrast", 0f);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var aR = colorA.R / 255f; var aG = colorA.G / 255f; var aB = colorA.B / 255f;
var bR = colorB.R / 255f; var bG = colorB.G / 255f; var bB = colorB.B / 255f;

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // Center the coordinate system for concentric rings
    var cx = u - 0.5f;
    var cy = v - 0.5f;

    // Convert to polar: radius and angle
    var radius = MathF.Sqrt(cx * cx + cy * cy);
    var angle = MathF.Atan2(cy, cx);

    // Ring perturbation using angular noise (creates wavy rings)
    var perturb = TileableFractalNoise(
        MathF.Cos(angle) * 0.5f + 0.5f,
        MathF.Sin(angle) * 0.5f + 0.5f,
        density * 2, 3, 0.6f, 2f, seed) - 0.5f;

    // Radial perturbation creates organic ring shapes (knots/burls)
    var radialNoise = TileableFractalNoise(u * 3f, v * 3f,
        3, 2, 0.5f, 2f, seed + 100);
    radius += (radialNoise - 0.5f) * ringDistort * 0.3f;
    radius += perturb * ringDistort * 0.15f;

    // Map radius to ring pattern
    var ringPos = radius * density;
    var localRing = ringPos - MathF.Floor(ringPos);

    // Grain: high-frequency noise along the ring tangent
    var grainNoise = TileableFractalNoise(u * 8f, v * 8f,
        8, 2, 0.5f, 2.5f, seed + 200);
    var grain = (grainNoise - 0.5f) * grainContrast * 0.4f;

    // Ring shape with sharpness control
    var ringVal = MathF.Sin(localRing * MathF.PI);
    ringVal = MathF.Pow(MathF.Abs(ringVal), 1f - ringSharpness * 0.7f);
    ringVal = Math.Clamp(ringVal + grain, 0f, 1f);

    // Color with variation
    var cellHash = HashToUnit((int)(ringPos * 7), (int)(ringPos * 13), seed + 50);
    var varAmt = (cellHash - 0.5f) * colorVar;
    var r = Lerp(aR + varAmt, bR, ringVal);
    var g = Lerp(aG + varAmt * 0.8f, bG, ringVal);
    var b = Lerp(aB + varAmt * 0.6f, bB, ringVal);

    // Brightness and contrast
    r = Math.Clamp(r + brightness, 0f, 1f);
    g = Math.Clamp(g + brightness, 0f, 1f);
    b = Math.Clamp(b + brightness, 0f, 1f);
    if (contrast > 0f)
    {
        var mid = 0.5f;
        r = Lerp(mid, r, 1f + contrast);
        g = Lerp(mid, g, 1f + contrast);
        b = Lerp(mid, b, 1f + contrast);
    }

    if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

    buffer.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return buffer;
}
